import Vue from "vue";
import Router from "vue-router";
import Home from "../views/Home.vue";
import Game from "../views/Game.vue";
import Control from '../views/Control.vue';
import Final from '../views/Final.vue';
import Credits from "../views/Credits.vue";
import Tutorial from '../views/Tutorial.vue';

Vue.use(Router);

const router = new Router({
	routes: [
		{
			path: '/home',
			name: 'home',
			component: Home,
		},
		{
			path: '/game',
			name: 'game',
			component: Game,
		},
		{
			path: '/control',
			name: 'control',
			component: Control,
		},
		{
			path: '/final',
			name: 'final',
			component: Final,
		},
		{
			path: '/credits',
			name: 'credits',
			component: Credits,
		},
		{
			path: '/tutorial',
			name: 'tutorial',
			component: Tutorial,
		},
		{
			path: '*',
			component: Home,
		},
	],
});

// If there's saved progress, skip home and go straight to game
router.beforeEach((to, from, next) => {
	const isHome = to.name === 'home' || (to.matched.length > 0 && to.matched[0].components.default === Home);
	if (isHome) {
		try {
			const saved = JSON.parse(localStorage.getItem('palette-state'));
			if (saved && saved.tutorialIsLaunched && saved.level > 0 && saved.lives > 0) {
				return next({ name: 'game' });
			}
		} catch (e) {}
	}
	next();
});

export default router;
